                mLog.info(TAG, "xxxxx");
                mDownloadController.stopDownload();
        }
}

public class RunClass{
        public static void main(String[] args){
                IDownload downloadController = new DownloadProxy(new DownloadImpl);
                download.startDownload();
        }
}
```

